def load_bfm():
    global _cache
    if _cache is None:
        raw = zlib.decompress(base64.b64decode(_BFM_B64))
        data = np.load(io.BytesIO(raw))
        _cache = {
            'u_base': data['u_base'],
            'w_shp_base': data['w_shp_base'],
            'w_exp_base': data['w_exp_base'],
            'param_mean': data['param_mean'],
            'param_std': data['param_std'],
        }
    return _cache
